33		public async getTrendingProductsByCategory({
34			categoryId,
35			excludeProductIds,
36			limit = 12,
37			offset = 0,
38		}: {
39			categoryId: number;
40			excludeProductIds?: number[];
41			limit?: number;
42			offset?: number;
43		}): Promise<TrendingProductsByCategoryResponseDto> {
44			this.logger.debug(
45				'[getTrendingProductsByCategory] Starting trending products fetch',
46				{
47					categoryId,
48					limit,
49					offset,
50					excludeCount: excludeProductIds?.length ?? 0,
51				},
52			);
53	
54			try {
55				const mergedExcludeProductIds = [
56					...ALWAYS_TRENDING_PRODUCTS_EXCLUDED_LIST,
57					...(excludeProductIds ?? []),
58				];
59	
60				const params: {
61					categoryId: number;
62					excludeProductIds?: number[];
63					limit?: number;
64					offset?: number;
65				} = { categoryId, limit, offset, excludeProductIds: mergedExcludeProductIds };
66	
67				const trendingProductsList =
68					await this.forecastedTrendingProductsService.getTrendingProductsByCategory(
69						params,
70					);
71				this.logger.debug('[getTrendingProductsByCategory] DB query complete', {
72					count: trendingProductsList.length,
73				});
74	
75				const styleIds = trendingProductsList.map((item) => item.style_id);
76	
77				const { products, mvRecords } =
78					await this.productHydrationService.hydrateProductsWithColors({
79						styleIds,
80					});
81	
82				this.logger.debug('MV returned products', {
83					categoryId,
84					returnedCount: products.length,
85					requestedCount: trendingProductsList.length,
86				});
87	
88				const trendingProducts = products.map((product) => {
89					const mv = mvRecords.get(product.style_id);
90					const colors = this.productHydrationService.convertMvColorsToProductColors({
91						colors: mv?.colors ?? null,
92					});
93					return assignRandomColorToProduct({ product, availableColors: colors });
94				});
95	
96				return { trendingProducts, categoryId, limit, offset };
97			} catch (error) {
98				this.logger.error(
99					`Error fetching trending products for category ${categoryId}: ${(error as Error).message}`,
100					(error as Error).stack,
101				);
102				throw error;
103			}
104		}
