199		public forecastStyleTrend({
200			styleId,
201			historicalData,
202			startDate,
203			endDate,
204			forecastDays,
205			bar,
206		}: {
207			styleId: number;
208			historicalData: IProductAnnualSalesBase[];
209			startDate: string;
210			endDate: string;
211			forecastDays: number;
212			bar?: ProgressBar;
213		}): CompleteForecastResult | null {
214			try {
215				const endDateDayNumber = this.getDayOfYear(new Date(endDate));
216	
217				const purchasesArr = historicalData.reduce<number[]>((acc, data, index) => {
218					if (index === historicalData.length - 1) {
219						acc.push(...data.daily_orders.slice(0, endDateDayNumber));
220					} else {
221						acc.push(...data.daily_orders);
222					}
223					return acc;
224				}, []);
225	
226				const smoothedPurchasesArr = MathematicalFunctions.exponentialSmoothing({
227					values: purchasesArr,
228					alpha: 0.1,
229				});
230	
231				const harmonics = this.getHarmonicsByObservationsCount({
232					observations: smoothedPurchasesArr.length,
233				});
234	
235				const changes = MathematicalFunctions.changePointDetection({
236					values: smoothedPurchasesArr,
237					significance: 0.02,
238					penalty: 0.1,
239					minSegmentLength: 40,
240				});
241	
242				const yearlyComponent = this.calculateSeasonalComponent({
243					values: smoothedPurchasesArr,
244					period: 365,
245					harmonics,
246				});
247	
248				const monthlyComponent = this.calculateSeasonalComponent({
249					values: smoothedPurchasesArr,
250					period: 30,
251					harmonics,
252				});
253	
254				const weeklyComponent = this.calculateSeasonalComponent({
255					values: smoothedPurchasesArr,
256					period: 7,
257					harmonics,
258				});
259	
260				const quarterlyComponent = this.calculateSeasonalComponent({
261					values: smoothedPurchasesArr,
262					period: 91,
263					harmonics,
264				});
265	
266				const trendComponent = this.calculateTrendComponent({
267					values: smoothedPurchasesArr,
268					changePoints: changes.changePoints,
269					startDate: startDate,
270					endDate: endDate,
271				});
272	
273				const residuals = purchasesArr.map((val, i) => {
274					const trend = trendComponent[i] ?? 0;
275					const yearly = yearlyComponent[i] ?? 0;
276					const monthly = monthlyComponent[i] ?? 0;
277					const weekly = weeklyComponent[i] ?? 0;
278					const quarterly = quarterlyComponent[i] ?? 0;
279					return val - (trend + yearly + monthly + weekly + quarterly);
280				});
281	
282				const smoothedResidualsArr = MathematicalFunctions.exponentialSmoothing({
283					values: residuals,
284					alpha: 0.1,
285				});
286	
287				const comprehensiveForecast = this.createComprehensiveForecast({
288					yearlyComponent,
289					monthlyComponent,
290					weeklyComponent,
291					quarterlyComponent,
292					trendComponent,
293					smoothedResidualsArr,
294					historicalLength: purchasesArr.length,
295					forecastDays,
296					endDate,
297					purchasesArr,
298				});
299	
300				const historicalWindow = 14;
301				const historicalOrders = purchasesArr.slice(-historicalWindow);
302	
303				const trendingScoreData = {
304					historicalOrders,
305					forecastedOrders: comprehensiveForecast.forecastValues,
306					trendComponent,
307				};
308	
309				const trendingResult =
310					TrendingScoreCalculator.calculateTrendingScore(trendingScoreData);
311	
312				const trendScore = trendingResult.trendScore;
313	
314				const { trendingReason } = this.calculateTrendingReason({
315					comprehensiveForecast,
316					historicalOrders,
317					trendComponent,
318				});
319	
320				const finalTrendingReason = trendingReason;
321	
322				const forecastResult: CompleteForecastResult = {
323					style_id: styleId,
324					forecast_dates: comprehensiveForecast.forecastDates,
325					predicted_orders: comprehensiveForecast.forecastValues,
326					trend_score: Math.round(trendScore * 100) / 100,
327					trending_reason: finalTrendingReason,
328					purchasesArr,
329					smoothedPurchasesArr,
330					yearlyComponent,
331					monthlyComponent,
332					weeklyComponent,
333					quarterlyComponent,
334					trendComponent,
335					smoothedResidualsArr,
336					comprehensiveForecast,
337					changes,
338					startDate,
339					endDate,
340				};
341	
342				if (bar) {
343					bar.increment({ by: 1 });
344				}
345	
346				return forecastResult;
347			} catch (error) {
348				this.logger.error(
349					`Error processing product ${styleId}: ${(error as Error).message}`,
350					(error as Error).stack,
351				);
352				if (bar) {
353					bar.increment({ by: 1 });
354				}
355				return null;
356			}
357		}
