373		public async saveBatchResults(
374			results: CompleteForecastResult[],
375			startDate: string,
376			endDate: string,
377			forecastDays: number,
378		): Promise<void> {
379			if (results.length === 0) return;
380	
381			try {
382				const dbPredictions: ITrendingProductsCreate[] = results
383					.map((result) => {
384						let predictedOrders = result.predicted_orders;
385						let actualForecastDays = forecastDays;
386	
387						if (forecastDays === 9 && predictedOrders.length === 9) {
388							predictedOrders = predictedOrders.slice(-7);
389							actualForecastDays = 7;
390						}
391	
392						const totalPredictedOrders = predictedOrders.reduce(
393							(sum, value) => sum + value,
394							0,
395						);
396	
397						return {
398							style_id: result.style_id,
399							predicted_orders: predictedOrders,
400							total_predicted_orders: totalPredictedOrders,
401							trend_score: result.trend_score,
402							trending_reason: result.trending_reason,
403							forecast_start_date: startDate,
404							forecast_end_date: endDate,
405							forecast_days: actualForecastDays,
406						};
407					})
408					.filter(
409						(data) =>
410							typeof data.trend_score === 'number' && !Number.isNaN(data.trend_score),
411					);
412	
413				await this.forecastedTrendingProductsService.saveBatchPredictions({
414					predictions: dbPredictions,
415				});
416			} catch (error) {
417				this.logger.error(
418					`Failed to save batch predictions to database: ${(error as Error).message}`,
419					(error as Error).stack,
420				);
421			}
422		}
