646		private extendSeasonalComponent(
647			component: number[],
648			period: number,
649			harmonics: number,
650			historicalLength: number,
651			forecastDates: string[],
652			endDate: string,
653		): number[] {
654			if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
655	
656			try {
657				const coefficients = MathematicalFunctions.fourierCoefficients({
658					values: component,
659					period,
660					harmonics,
661					precision: null,
662				});
663	
664				const forecastValues: number[] = [];
665				const endDateObj = new Date(endDate);
666	
667				for (const forecastDate of forecastDates) {
668					const forecastDateObj = new Date(forecastDate);
669	
670					const daysDiff = Math.floor(
671						(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
672					);
673	
674					const cyclePosition = (historicalLength + daysDiff) % period;
675					const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
676						period,
677						harmonics,
678						a: coefficients.a,
679						b: coefficients.b,
680						length: Math.ceil(cyclePosition) + 1,
681						a0: 0,
682					});
683	
684					const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
685					forecastValues.push(seasonalValue);
686				}
687	
688				return forecastValues;
689			} catch (error) {
690				this.logger.error(
691					`Error extending seasonal component: ${(error as Error).message}`,
692					(error as Error).stack,
693				);
694				return forecastDates.map((forecastDate) => {
695					const endDateObj = new Date(endDate);
696					const forecastDateObj = new Date(forecastDate);
697					const daysDiff = Math.floor(
698						(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
699					);
700					const flooredPeriod = Math.max(1, Math.floor(period));
701					const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
702					const historicalIndex = Math.min(cyclePosition, component.length - 1);
703					return component[historicalIndex] ?? 0;
704				});
705			}
706		}
707	
708		private extendTrendComponent(trendComponent: number[], forecastDays: number): number[] {
709			if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];
710	
711			const recentTrendPoints = Math.min(30, trendComponent.length);
712			const recentTrend = trendComponent.slice(-recentTrendPoints);
713	
714			const x = Array.from({ length: recentTrend.length }, (_, i) => i);
715			const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
716	
717			const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
718			const trendSlope = regression.slope;
719	
720			return Array(forecastDays)
721				.fill(0)
722				.map((_, i) => {
723					const decay = Math.exp(-0.02 * i);
724					return lastValue + trendSlope * (i + 1) * decay;
725				});
726		}
727	
728		private extendResidualsComponent({
729			smoothedResidualsArr,
730			forecastDays,
731			endDate,
732		}: {
733			smoothedResidualsArr: number[];
734			forecastDays: number;
735			endDate: string;
736		}): number[] {
737			if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
738				return Array(forecastDays).fill(0) as number[];
739			}
740	
741			const twoWeeksLength = 7;
742			const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
743			const recentResiduals = smoothedResidualsArr.slice(-trendLength);
744	
745			const endDateObj = new Date(endDate);
746			const dates = recentResiduals.map((_, i) => {
747				const date = new Date(endDateObj);
748				date.setDate(endDateObj.getDate() - (trendLength - i - 1));
749				const dateArr = date.toISOString().split('T') as [string, string];
750				return dateArr[0];
751			});
752	
753			const trendValues = MathematicalFunctions.calculateTrend({
754				values: recentResiduals,
755				dates,
756			});
757	
758			if (trendValues.length === 0) {
759				return Array(forecastDays).fill(0) as number[];
760			}
761	
762			const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
763			const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });
764	
765			const lastIndex = recentResiduals.length - 1;
766			return Array(forecastDays)
767				.fill(0)
768				.map((_, i) => {
769					return regression.slope * (lastIndex + i + 1) + regression.intercept;
770				});
771		}
772	
773		private getDayOfYear(date = new Date()) {
774			const start = new Date(Date.UTC(date.getFullYear(), 0, 1));
775			const current = new Date(
776				Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()),
777			);
778	
779			return Math.floor((current.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
780		}
781	
782		private generateFutureDates(endDate: string, forecastDays: number): string[] {
783			const dates: string[] = [];
784			const startDate = new Date(endDate);
785	
786			for (let i = 1; i <= forecastDays; i++) {
787				const futureDate = new Date(startDate);
788				futureDate.setDate(startDate.getDate() + i);
789				const dateArr = futureDate.toISOString().split('T') as [string, string];
790				dates.push(dateArr[0]);
791			}
792	
793			return dates;
794		}
795	
796		private calculateTrendingReason({
797			comprehensiveForecast,
798			historicalOrders,
799			trendComponent,
800		}: {
801			comprehensiveForecast: {
802				forecastValues: number[];
803				forecastDates: string[];
804				components: {
805					yearly: number[];
806					monthly: number[];
807					weekly: number[];
808					quarterly: number[];
809					trend: number[];
810					residuals: number[];
811				};
812			};
813			historicalOrders: number[];
814			trendComponent: number[];
815		}): { trendingReason: string; growthRate: number } {
816			if (
817				historicalOrders.length === 0 ||
818				comprehensiveForecast.forecastValues.length === 0
819			) {
820				return { trendingReason: 'Stable pattern', growthRate: 0 };
821			}
822	
823			const historicalAvg =
824				historicalOrders.reduce((sum, val) => sum + val, 0) / historicalOrders.length;
825			const forecastAvg =
826				comprehensiveForecast.forecastValues.reduce((sum, val) => sum + val, 0) /
827				comprehensiveForecast.forecastValues.length;
828	
829			const growthRate =
830				historicalAvg > 0 ? (forecastAvg - historicalAvg) / historicalAvg : 0;
831	
832			const trendSlope = this.calculateTrendSlope(trendComponent);
833	
834			if (growthRate > 0.2 || forecastAvg > historicalAvg * 1.2) {
835				return { trendingReason: 'Strong growth forecast', growthRate };
836			} else if (growthRate > 0.1 || forecastAvg > historicalAvg * 1.1) {
837				return { trendingReason: 'Moderate growth forecast', growthRate };
838			} else if (growthRate > 0 || trendSlope >= 0.05) {
839				return { trendingReason: 'Positive trend detected', growthRate };
840			} else {
841				return { trendingReason: 'Stable pattern', growthRate };
842			}
843		}
844	
845		private calculateTrendSlope(trendComponent: number[]): number {
846			if (trendComponent.length < 2) return 0;
847	
848			const recentPoints = Math.min(14, trendComponent.length);
849			const recentTrend = trendComponent.slice(-recentPoints);
850	
851			const x = Array.from({ length: recentTrend.length }, (_, i) => i);
852			const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
853	
854			return regression.slope;
855		}
856	}
