198		public forecastStyleTrend({
199			styleId,
200			historicalData,
201			startDate,
202			endDate,
203			forecastDays,
204			bar,
205		}: {
206			styleId: number;
207			historicalData: IProductAnnualSalesBase[];
208			startDate: string;
209			endDate: string;
210			forecastDays: number;
211			bar?: ProgressBar;
212		}): CompleteForecastResult | null {
213			try {
214				const endDateDayNumber = this.getDayOfYear(new Date(endDate));
215	
216				const purchasesArr = historicalData.reduce<number[]>((acc, data, index) => {
217					if (index === historicalData.length - 1) {
218						acc.push(...data.daily_orders.slice(0, endDateDayNumber));
219					} else {
220						acc.push(...data.daily_orders);
221					}
222					return acc;
223				}, []);
224	
225				const smoothedPurchasesArr = MathematicalFunctions.exponentialSmoothing({
226					values: purchasesArr,
227					alpha: 0.1,
228				});
229	
230				const harmonics = this.getHarmonicsByObservationsCount({
231					observations: smoothedPurchasesArr.length,
232				});
233	
234				const changes = MathematicalFunctions.changePointDetection({
235					values: smoothedPurchasesArr,
236					significance: 0.02,
237					penalty: 0.1,
238					minSegmentLength: 40,
239				});
240	
241				const yearlyComponent = this.calculateSeasonalComponent({
242					values: smoothedPurchasesArr,
243					period: 365,
244					harmonics,
245				});
246	
247				const monthlyComponent = this.calculateSeasonalComponent({
248					values: smoothedPurchasesArr,
249					period: 30,
250					harmonics,
251				});
252	
253				const weeklyComponent = this.calculateSeasonalComponent({
254					values: smoothedPurchasesArr,
255					period: 7,
256					harmonics,
257				});
258	
259				const quarterlyComponent = this.calculateSeasonalComponent({
260					values: smoothedPurchasesArr,
261					period: 91,
262					harmonics,
263				});
264	
265				const trendComponent = this.calculateTrendComponent({
266					values: smoothedPurchasesArr,
267					changePoints: changes.changePoints,
268					startDate: startDate,
269					endDate: endDate,
270				});
271	
272				const residuals = purchasesArr.map((val, i) => {
273					const trend = trendComponent[i] ?? 0;
274					const yearly = yearlyComponent[i] ?? 0;
275					const monthly = monthlyComponent[i] ?? 0;
276					const weekly = weeklyComponent[i] ?? 0;
277					const quarterly = quarterlyComponent[i] ?? 0;
278					return val - (trend + yearly + monthly + weekly + quarterly);
279				});
280	
281				const smoothedResidualsArr = MathematicalFunctions.exponentialSmoothing({
282					values: residuals,
283					alpha: 0.1,
284				});
285	
286				const comprehensiveForecast = this.createComprehensiveForecast({
287					yearlyComponent,
288					monthlyComponent,
289					weeklyComponent,
290					quarterlyComponent,
291					trendComponent,
292					smoothedResidualsArr,
293					historicalLength: purchasesArr.length,
294					forecastDays,
295					endDate,
296					purchasesArr,
297				});
298	
299				const historicalWindow = 14;
300				const historicalOrders = purchasesArr.slice(-historicalWindow);
301	
302				const trendingScoreData = {
303					historicalOrders,
304					forecastedOrders: comprehensiveForecast.forecastValues,
305					trendComponent,
306				};
307	
308				const trendingResult =
309					TrendingScoreCalculator.calculateTrendingScore(trendingScoreData);
310	
311				const trendScore = trendingResult.trendScore;
312	
313				const { trendingReason } = this.calculateTrendingReason({
314					comprehensiveForecast,
315					historicalOrders,
316					trendComponent,
317				});
318	
319				const finalTrendingReason = trendingReason;
320	
321				const forecastResult: CompleteForecastResult = {
322					style_id: styleId,
323					forecast_dates: comprehensiveForecast.forecastDates,
324					predicted_orders: comprehensiveForecast.forecastValues,
325					trend_score: Math.round(trendScore * 100) / 100,
326					trending_reason: finalTrendingReason,
327					purchasesArr,
328					smoothedPurchasesArr,
329					yearlyComponent,
330					monthlyComponent,
331					weeklyComponent,
332					quarterlyComponent,
333					trendComponent,
334					smoothedResidualsArr,
335					comprehensiveForecast,
336					changes,
337					startDate,
338					endDate,
339				};
340	
341				if (bar) {
342					bar.increment({ by: 1 });
343				}
344	
345				return forecastResult;
346			} catch (error) {
347				this.logger.error(
348					`Error processing product ${styleId}: ${(error as Error).message}`,
349					(error as Error).stack,
350				);
351				if (bar) {
352					bar.increment({ by: 1 });
353				}
354				return null;
355			}
356		}
