423		private calculateSeasonalComponent({
424			values,
425			period,
426			harmonics,
427		}: {
428			values: number[];
429			period: number;
430			harmonics: number;
431		}): number[] {
432			const n = values.length;
433			if (n < period) {
434				return new Array(n).fill(0) as number[];
435			}
436	
437			try {
438				const coefficients = MathematicalFunctions.fourierCoefficients({
439					values,
440					period,
441					harmonics,
442					precision: null,
443				});
444	
445				const seasonal = MathematicalFunctions.reconstructFourierSeries({
446					period,
447					harmonics,
448					a: coefficients.a,
449					b: coefficients.b,
450					length: n,
451				});
452	
453				return seasonal;
454			} catch (error) {
455				this.logger.error(
456					`Error extending seasonal component: ${(error as Error).message}`,
457					(error as Error).stack,
458				);
459				return values.map((_, index) => {
460					const cyclePosition = index % Math.max(1, Math.floor(period));
461					const seasonalIndex = Math.min(cyclePosition, values.length - 1);
462					return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
463				});
464			}
465		}
466	
467		private calculateTrendComponent({
468			values,
469			changePoints,
470			startDate,
471			endDate,
472		}: {
473			values: number[];
474			changePoints: number[];
475			startDate: string;
476			endDate: string;
477		}): number[] {
478			const n = values.length;
479			if (n === 0) return [];
480	
481			const dates = this.generateDateRange(startDate, endDate, n);
482	
483			if (changePoints.length === 0) {
484				return MathematicalFunctions.calculateTrend({ values, dates });
485			}
486	
487			const trend = new Array(n).fill(0) as number[];
488			const segments = [0, ...changePoints, n];
489	
490			for (let i = 0; i < segments.length - 1; i++) {
491				const start = segments[i] as unknown as number;
492				const end = segments[i + 1] as unknown as number;
493				const segmentValues = values.slice(start, end);
494				const segmentDates = dates.slice(start, end);
495	
496				if (segmentValues.length > 1) {
497					const segmentTrend = MathematicalFunctions.calculateTrend({
498						values: segmentValues,
499						dates: segmentDates,
500					});
501	
502					for (let j = 0; j < segmentTrend.length; j++) {
503						trend[start + j] = segmentTrend[j] as unknown as number;
504					}
505				} else if (segmentValues.length === 1) {
506					trend[start] = segmentValues[0] as unknown as number;
507				}
508			}
509	
510			return trend;
511		}
512	
513		private generateDateRange(startDate: string, endDate: string, count: number): string[] {
514			const start = new Date(startDate);
515			const end = new Date(endDate);
516			const totalDays =
517				Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
518			const step = totalDays / count;
519	
520			const dates: string[] = [];
521			for (let i = 0; i < count; i++) {
522				const currentDate = new Date(start.getTime() + i * step * 24 * 60 * 60 * 1000);
523				const dateArr = currentDate.toISOString().split('T') as [string, string];
524				dates.push(dateArr[0]);
525			}
526			return dates;
527		}
