529		private createComprehensiveForecast({
530			yearlyComponent,
531			monthlyComponent,
532			weeklyComponent,
533			quarterlyComponent,
534			trendComponent,
535			smoothedResidualsArr,
536			historicalLength,
537			forecastDays,
538			endDate,
539		}: {
540			yearlyComponent: number[];
541			monthlyComponent: number[];
542			weeklyComponent: number[];
543			quarterlyComponent: number[];
544			trendComponent: number[];
545			smoothedResidualsArr: number[];
546			historicalLength: number;
547			forecastDays: number;
548			endDate: string;
549			purchasesArr: number[];
550		}): {
551			forecastValues: number[];
552			forecastDates: string[];
553			components: {
554				yearly: number[];
555				monthly: number[];
556				weekly: number[];
557				quarterly: number[];
558				trend: number[];
559				residuals: number[];
560			};
561		} {
562			const forecastDates = this.generateFutureDates(endDate, forecastDays);
563	
564			const harmonics = this.getHarmonicsByObservationsCount({
565				observations: historicalLength,
566			});
567	
568			const extendedYearly = this.extendSeasonalComponent(
569				yearlyComponent,
570				365,
571				harmonics,
572				historicalLength,
573				forecastDates,
574				endDate,
575			);
576			const extendedMonthly = this.extendSeasonalComponent(
577				monthlyComponent,
578				30,
579				harmonics,
580				historicalLength,
581				forecastDates,
582				endDate,
583			);
584			const extendedWeekly = this.extendSeasonalComponent(
585				weeklyComponent,
586				7,
587				harmonics,
588				historicalLength,
589				forecastDates,
590				endDate,
591			);
592			const extendedQuarterly = this.extendSeasonalComponent(
593				quarterlyComponent,
594				91,
595				harmonics,
596				historicalLength,
597				forecastDates,
598				endDate,
599			);
600	
601			const extendedResiduals = this.extendResidualsComponent({
602				smoothedResidualsArr,
603				forecastDays,
604				endDate,
605			});
606	
607			const extendedTrend = this.extendTrendComponent(trendComponent, forecastDays);
608	
609			const forecastValues = Array(forecastDays)
610				.fill(0)
611				.map((_, i) => {
612					const yearly = extendedYearly[i] ?? 0;
613					const monthly = extendedMonthly[i] ?? 0;
614					const weekly = extendedWeekly[i] ?? 0;
615					const quarterly = extendedQuarterly[i] ?? 0;
616					const trend = extendedTrend[i] ?? 0;
617					const residual = extendedResiduals[i] ?? 0;
618					const forecastValue = trend + yearly + monthly + weekly + quarterly + residual;
619					return Math.max(0, forecastValue);
620				});
621	
622			return {
623				forecastValues,
624				forecastDates,
625				components: {
626					yearly: extendedYearly,
627					monthly: extendedMonthly,
628					weekly: extendedWeekly,
629					quarterly: extendedQuarterly,
630					trend: extendedTrend,
631					residuals: extendedResiduals,
632				},
633			};
634		}
