645		private extendSeasonalComponent(
646			component: number[],
647			period: number,
648			harmonics: number,
649			historicalLength: number,
650			forecastDates: string[],
651			endDate: string,
652		): number[] {
653			if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
654	
655			try {
656				const coefficients = MathematicalFunctions.fourierCoefficients({
657					values: component,
658					period,
659					harmonics,
660					precision: null,
661				});
662	
663				const forecastValues: number[] = [];
664				const endDateObj = new Date(endDate);
665	
666				for (const forecastDate of forecastDates) {
667					const forecastDateObj = new Date(forecastDate);
668	
669					const daysDiff = Math.floor(
670						(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
671					);
672	
673					const cyclePosition = (historicalLength + daysDiff) % period;
674					const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
675						period,
676						harmonics,
677						a: coefficients.a,
678						b: coefficients.b,
679						length: Math.ceil(cyclePosition) + 1,
680						a0: 0,
681					});
682	
683					const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
684					forecastValues.push(seasonalValue);
685				}
686	
687				return forecastValues;
688			} catch (error) {
689				this.logger.error(
690					`Error extending seasonal component: ${(error as Error).message}`,
691					(error as Error).stack,
692				);
693				return forecastDates.map((forecastDate) => {
694					const endDateObj = new Date(endDate);
695					const forecastDateObj = new Date(forecastDate);
696					const daysDiff = Math.floor(
697						(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
698					);
699					const flooredPeriod = Math.max(1, Math.floor(period));
700					const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
701					const historicalIndex = Math.min(cyclePosition, component.length - 1);
702					return component[historicalIndex] ?? 0;
703				});
704			}
705		}
706	
707		private extendTrendComponent(trendComponent: number[], forecastDays: number): number[] {
708			if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];
709	
710			const recentTrendPoints = Math.min(30, trendComponent.length);
711			const recentTrend = trendComponent.slice(-recentTrendPoints);
712	
713			const x = Array.from({ length: recentTrend.length }, (_, i) => i);
714			const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
715	
716			const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
717			const trendSlope = regression.slope;
718	
719			return Array(forecastDays)
720				.fill(0)
721				.map((_, i) => {
722					const decay = Math.exp(-0.02 * i);
723					return lastValue + trendSlope * (i + 1) * decay;
724				});
725		}
726	
727		private extendResidualsComponent({
728			smoothedResidualsArr,
729			forecastDays,
730			endDate,
731		}: {
732			smoothedResidualsArr: number[];
733			forecastDays: number;
734			endDate: string;
735		}): number[] {
736			if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
737				return Array(forecastDays).fill(0) as number[];
738			}
739	
740			const twoWeeksLength = 7;
741			const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
742			const recentResiduals = smoothedResidualsArr.slice(-trendLength);
743	
744			const endDateObj = new Date(endDate);
745			const dates = recentResiduals.map((_, i) => {
746				const date = new Date(endDateObj);
747				date.setDate(endDateObj.getDate() - (trendLength - i - 1));
748				const dateArr = date.toISOString().split('T') as [string, string];
749				return dateArr[0];
750			});
751	
752			const trendValues = MathematicalFunctions.calculateTrend({
753				values: recentResiduals,
754				dates,
755			});
756	
757			if (trendValues.length === 0) {
758				return Array(forecastDays).fill(0) as number[];
759			}
760	
761			const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
762			const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });
763	
764			const lastIndex = recentResiduals.length - 1;
765			return Array(forecastDays)
766				.fill(0)
767				.map((_, i) => {
768					return regression.slope * (lastIndex + i + 1) + regression.intercept;
769				});
770		}
