772		private getDayOfYear(date = new Date()) {
773			const start = new Date(Date.UTC(date.getFullYear(), 0, 1));
774			const current = new Date(
775				Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()),
776			);
777	
778			return Math.floor((current.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
779		}
780	
781		private generateFutureDates(endDate: string, forecastDays: number): string[] {
782			const dates: string[] = [];
783			const startDate = new Date(endDate);
784	
785			for (let i = 1; i <= forecastDays; i++) {
786				const futureDate = new Date(startDate);
787				futureDate.setDate(startDate.getDate() + i);
788				const dateArr = futureDate.toISOString().split('T') as [string, string];
789				dates.push(dateArr[0]);
790			}
791	
792			return dates;
793		}
794	
795		private calculateTrendingReason({
796			comprehensiveForecast,
797			historicalOrders,
798			trendComponent,
799		}: {
800			comprehensiveForecast: {
801				forecastValues: number[];
802				forecastDates: string[];
803				components: {
804					yearly: number[];
805					monthly: number[];
806					weekly: number[];
807					quarterly: number[];
808					trend: number[];
809					residuals: number[];
810				};
811			};
812			historicalOrders: number[];
813			trendComponent: number[];
814		}): { trendingReason: string; growthRate: number } {
815			if (
816				historicalOrders.length === 0 ||
817				comprehensiveForecast.forecastValues.length === 0
818			) {
819				return { trendingReason: 'Stable pattern', growthRate: 0 };
820			}
821	
822			const historicalAvg =
823				historicalOrders.reduce((sum, val) => sum + val, 0) / historicalOrders.length;
824			const forecastAvg =
825				comprehensiveForecast.forecastValues.reduce((sum, val) => sum + val, 0) /
826				comprehensiveForecast.forecastValues.length;
827	
828			const growthRate =
829				historicalAvg > 0 ? (forecastAvg - historicalAvg) / historicalAvg : 0;
830	
831			const trendSlope = this.calculateTrendSlope(trendComponent);
832	
833			if (growthRate > 0.2 || forecastAvg > historicalAvg * 1.2) {
834				return { trendingReason: 'Strong growth forecast', growthRate };
835			} else if (growthRate > 0.1 || forecastAvg > historicalAvg * 1.1) {
836				return { trendingReason: 'Moderate growth forecast', growthRate };
837			} else if (growthRate > 0 || trendSlope >= 0.05) {
838				return { trendingReason: 'Positive trend detected', growthRate };
839			} else {
840				return { trendingReason: 'Stable pattern', growthRate };
841			}
842		}
