import { Injectable, Logger } from '@nestjs/common';

import { ForecastedTrendingProductsService } from '@modules/db/forecasted-trending-products/forecasted-trending-products.service';
import { ITrendingProductsCreate } from '@modules/db/forecasted-trending-products/types/forecasted-trending-products.base.interface';
import { ProductAnnualSalesService } from '@modules/db/product-annual-sales/product-annual-sales.service';
import { IProductAnnualSalesBase } from '@modules/db/product-annual-sales/types/product-annual-sales.base.interface';
import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';

import { MathematicalFunctions } from '@utils/mathematical-functions.util';
import { ProgressBar } from '@utils/progress-bar.util';
import { assignRandomColorToProduct } from '@utils/random-color-picker.util';
import { TrendingScoreCalculator } from '@utils/trending-score-calculator.util';

import { ALWAYS_TRENDING_PRODUCTS_EXCLUDED_LIST } from '@constants/recommendations.constants';

import { CompleteForecastResult } from '@interfaces/trending-products.interface';

import { LogExecution } from '@decorators/log-execution.decorator';

import { TrendingProductsByCategoryResponseDto } from '@dto/trending-products/trending-products-by-category-response.dto';
import { TrendingProductsSiteWideResponseDto } from '@dto/trending-products/trending-products-site-wide-response.dto';

@Injectable()
export class TrendingProductsService {
	private readonly logger = new Logger(TrendingProductsService.name);

	constructor(
		private readonly productAnnualSalesService: ProductAnnualSalesService,
		private readonly forecastedTrendingProductsService: ForecastedTrendingProductsService,
		private readonly productHydrationService: ProductHydrationService,
	) {}

	public async getTrendingProductsByCategory({
		categoryId,
		excludeProductIds,
		limit = 12,
		offset = 0,
	}: {
		categoryId: number;
		excludeProductIds?: number[];
		limit?: number;
		offset?: number;
	}): Promise<TrendingProductsByCategoryResponseDto> {
		this.logger.debug(
			'[getTrendingProductsByCategory] Starting trending products fetch',
			{
				categoryId,
				limit,
				offset,
				excludeCount: excludeProductIds?.length ?? 0,
			},
		);

		try {
			const mergedExcludeProductIds = [
				...ALWAYS_TRENDING_PRODUCTS_EXCLUDED_LIST,
				...(excludeProductIds ?? []),
			];

			const params: {
				categoryId: number;
				excludeProductIds?: number[];
				limit?: number;
				offset?: number;
			} = { categoryId, limit, offset, excludeProductIds: mergedExcludeProductIds };

			const trendingProductsList =
				await this.forecastedTrendingProductsService.getTrendingProductsByCategory(
					params,
				);
			this.logger.debug('[getTrendingProductsByCategory] DB query complete', {
				count: trendingProductsList.length,
			});

			const styleIds = trendingProductsList.map((item) => item.style_id);

			const { products, mvRecords } =
				await this.productHydrationService.hydrateProductsWithColors({
					styleIds,
				});

			this.logger.debug('MV returned products', {
				categoryId,
				returnedCount: products.length,
				requestedCount: trendingProductsList.length,
			});

			const trendingProducts = products.map((product) => {
				const mv = mvRecords.get(product.style_id);
				const colors = this.productHydrationService.convertMvColorsToProductColors({
					colors: mv?.colors ?? null,
				});
				return assignRandomColorToProduct({ product, availableColors: colors });
			});

			return { trendingProducts, categoryId, limit, offset };
		} catch (error) {
			this.logger.error(
				`Error fetching trending products for category ${categoryId}: ${(error as Error).message}`,
				(error as Error).stack,
			);
			throw error;
		}
	}

	@LogExecution({
		paramFormatter: ([params]: [
			{ excludeProductIds?: number[]; limit?: number; offset?: number },
		]) => ({
			excludeProductIds: params.excludeProductIds,
			limit: params.limit,
			offset: params.offset,
		}),
		responseFormatter: (res: TrendingProductsSiteWideResponseDto) => ({
			trendingProductsCount: res.trendingProducts.length,
		}),
	})
	public async getTrendingProductsSiteWide({
		excludeProductIds,
		limit = 30,
		offset = 0,
	}: {
		excludeProductIds?: number[];
		limit?: number;
		offset?: number;
	} = {}): Promise<TrendingProductsSiteWideResponseDto> {
		try {
			const mergedExcludeProductIds = [
				...ALWAYS_TRENDING_PRODUCTS_EXCLUDED_LIST,
				...(excludeProductIds ?? []),
			];

			const trendingProductsList =
				await this.forecastedTrendingProductsService.getTopTrendingProducts({
					limit: limit + mergedExcludeProductIds.length,
					offset,
				});
			const excludeSet = new Set(mergedExcludeProductIds);
			const filteredList = trendingProductsList
				.filter((item) => !excludeSet.has(item.style_id))
				.slice(0, limit);

			const styleIds = filteredList.map((item) => item.style_id);

			const { products, mvRecords } =
				await this.productHydrationService.hydrateProductsWithColors({ styleIds });

			const trendingProducts = products.map((product) => {
				const mv = mvRecords.get(product.style_id);
				const colors = this.productHydrationService.convertMvColorsToProductColors({
					colors: mv?.colors ?? null,
				});
				return assignRandomColorToProduct({ product, availableColors: colors });
			});

			return { trendingProducts, limit, offset };
		} catch (error) {
			this.logger.error(
				`Error fetching site-wide trending products: ${(error as Error).message}`,
				(error as Error).stack,
			);
			throw error;
		}
	}

	public async invalidateLatestForecasts(): Promise<void> {
		return this.forecastedTrendingProductsService.invalidateLatestForecasts();
	}

	public async deactivateOldPredictions(): Promise<void> {
		return this.forecastedTrendingProductsService.deactivateOldPredictions();
	}

	public async activateLatestPredictions(): Promise<void> {
		return this.forecastedTrendingProductsService.activateLatestPredictions();
	}

	public async getStyleIdsInDateRange({
		startDate,
		endDate,
	}: {
		startDate: string;
		endDate: string;
	}): Promise<IProductAnnualSalesBase[]> {
		const startYearStr = startDate.split('-')[0];
		const endYearStr = endDate.split('-')[0];

		if (!startYearStr || !endYearStr) {
			throw new Error(`Invalid date format: startDate=${startDate}, endDate=${endDate}`);
		}

		const startYear = parseInt(startYearStr, 10);
		const endYear = parseInt(endYearStr, 10);

		this.logger.log('Fetching style IDs from year range', { startYear, endYear });
		return await this.productAnnualSalesService.findByYearRange({ startYear, endYear });
	}

	public forecastStyleTrend({
		styleId,
		historicalData,
		startDate,
		endDate,
		forecastDays,
		bar,
	}: {
		styleId: number;
		historicalData: IProductAnnualSalesBase[];
		startDate: string;
		endDate: string;
		forecastDays: number;
		bar?: ProgressBar;
	}): CompleteForecastResult | null {
		try {
			const endDateDayNumber = this.getDayOfYear(new Date(endDate));

			const purchasesArr = historicalData.reduce<number[]>((acc, data, index) => {
				if (index === historicalData.length - 1) {
					acc.push(...data.daily_orders.slice(0, endDateDayNumber));
				} else {
					acc.push(...data.daily_orders);
				}
				return acc;
			}, []);

			const smoothedPurchasesArr = MathematicalFunctions.exponentialSmoothing({
				values: purchasesArr,
				alpha: 0.1,
			});

			const harmonics = this.getHarmonicsByObservationsCount({
				observations: smoothedPurchasesArr.length,
			});

			const changes = MathematicalFunctions.changePointDetection({
				values: smoothedPurchasesArr,
				significance: 0.02,
				penalty: 0.1,
				minSegmentLength: 40,
			});

			const yearlyComponent = this.calculateSeasonalComponent({
				values: smoothedPurchasesArr,
				period: 365,
				harmonics,
			});

			const monthlyComponent = this.calculateSeasonalComponent({
				values: smoothedPurchasesArr,
				period: 30,
				harmonics,
			});

			const weeklyComponent = this.calculateSeasonalComponent({
				values: smoothedPurchasesArr,
				period: 7,
				harmonics,
			});

			const quarterlyComponent = this.calculateSeasonalComponent({
				values: smoothedPurchasesArr,
				period: 91,
				harmonics,
			});

			const trendComponent = this.calculateTrendComponent({
				values: smoothedPurchasesArr,
				changePoints: changes.changePoints,
				startDate: startDate,
				endDate: endDate,
			});

			const residuals = purchasesArr.map((val, i) => {
				const trend = trendComponent[i] ?? 0;
				const yearly = yearlyComponent[i] ?? 0;
				const monthly = monthlyComponent[i] ?? 0;
				const weekly = weeklyComponent[i] ?? 0;
				const quarterly = quarterlyComponent[i] ?? 0;
				return val - (trend + yearly + monthly + weekly + quarterly);
			});

			const smoothedResidualsArr = MathematicalFunctions.exponentialSmoothing({
				values: residuals,
				alpha: 0.1,
			});

			const comprehensiveForecast = this.createComprehensiveForecast({
				yearlyComponent,
				monthlyComponent,
				weeklyComponent,
				quarterlyComponent,
				trendComponent,
				smoothedResidualsArr,
				historicalLength: purchasesArr.length,
				forecastDays,
				endDate,
				purchasesArr,
			});

			const historicalWindow = 14;
			const historicalOrders = purchasesArr.slice(-historicalWindow);

			const trendingScoreData = {
				historicalOrders,
				forecastedOrders: comprehensiveForecast.forecastValues,
				trendComponent,
			};

			const trendingResult =
				TrendingScoreCalculator.calculateTrendingScore(trendingScoreData);

			const trendScore = trendingResult.trendScore;

			const { trendingReason } = this.calculateTrendingReason({
				comprehensiveForecast,
				historicalOrders,
				trendComponent,
			});

			const finalTrendingReason = trendingReason;

			const forecastResult: CompleteForecastResult = {
				style_id: styleId,
				forecast_dates: comprehensiveForecast.forecastDates,
				predicted_orders: comprehensiveForecast.forecastValues,
				trend_score: Math.round(trendScore * 100) / 100,
				trending_reason: finalTrendingReason,
				purchasesArr,
				smoothedPurchasesArr,
				yearlyComponent,
				monthlyComponent,
				weeklyComponent,
				quarterlyComponent,
				trendComponent,
				smoothedResidualsArr,
				comprehensiveForecast,
				changes,
				startDate,
				endDate,
			};

			if (bar) {
				bar.increment({ by: 1 });
			}

			return forecastResult;
		} catch (error) {
			this.logger.error(
				`Error processing product ${styleId}: ${(error as Error).message}`,
				(error as Error).stack,
			);
			if (bar) {
				bar.increment({ by: 1 });
			}
			return null;
		}
	}

	@LogExecution({
		paramFormatter: ([params]: [
			{
				results: CompleteForecastResult[];
				startDate: string;
				endDate: string;
				forecastDays: number;
			},
		]) => ({
			resultCount: params.results.length,
			startDate: params.startDate,
			endDate: params.endDate,
			forecastDays: params.forecastDays,
		}),
		responseFormatter: () => ({ completed: true }),
	})
	public async saveBatchResults({
		results,
		startDate,
		endDate,
		forecastDays,
	}: {
		results: CompleteForecastResult[];
		startDate: string;
		endDate: string;
		forecastDays: number;
	}): Promise<void> {
		if (results.length === 0) return;

		try {
			const dbPredictions: ITrendingProductsCreate[] = results
				.map((result) => {
					let predictedOrders = result.predicted_orders;
					let actualForecastDays = forecastDays;

					if (forecastDays === 9 && predictedOrders.length === 9) {
						predictedOrders = predictedOrders.slice(-7);
						actualForecastDays = 7;
					}

					const totalPredictedOrders = predictedOrders.reduce(
						(sum, value) => sum + value,
						0,
					);

					return {
						style_id: result.style_id,
						predicted_orders: predictedOrders,
						total_predicted_orders: totalPredictedOrders,
						trend_score: result.trend_score,
						trending_reason: result.trending_reason,
						forecast_start_date: startDate,
						forecast_end_date: endDate,
						forecast_days: actualForecastDays,
					};
				})
				.filter(
					(data) =>
						typeof data.trend_score === 'number' && !Number.isNaN(data.trend_score),
				);

			await this.forecastedTrendingProductsService.saveBatchPredictions({
				predictions: dbPredictions,
			});
		} catch (error) {
			this.logger.error(
				`Failed to save batch predictions to database: ${(error as Error).message}`,
				(error as Error).stack,
			);
		}
	}

	private calculateSeasonalComponent({
		values,
		period,
		harmonics,
	}: {
		values: number[];
		period: number;
		harmonics: number;
	}): number[] {
		const n = values.length;
		if (n < period) {
			return new Array(n).fill(0) as number[];
		}

		try {
			const coefficients = MathematicalFunctions.fourierCoefficients({
				values,
				period,
				harmonics,
				precision: null,
			});

			const seasonal = MathematicalFunctions.reconstructFourierSeries({
				period,
				harmonics,
				a: coefficients.a,
				b: coefficients.b,
				length: n,
			});

			return seasonal;
		} catch (error) {
			this.logger.error(
				`Error extending seasonal component: ${(error as Error).message}`,
				(error as Error).stack,
			);
			return values.map((_, index) => {
				const cyclePosition = index % Math.max(1, Math.floor(period));
				const seasonalIndex = Math.min(cyclePosition, values.length - 1);
				return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
			});
		}
	}

	private calculateTrendComponent({
		values,
		changePoints,
		startDate,
		endDate,
	}: {
		values: number[];
		changePoints: number[];
		startDate: string;
		endDate: string;
	}): number[] {
		const n = values.length;
		if (n === 0) return [];

		const dates = this.generateDateRange({ startDate, endDate, count: n });

		if (changePoints.length === 0) {
			return MathematicalFunctions.calculateTrend({ values, dates });
		}

		const trend = new Array(n).fill(0) as number[];
		const segments = [0, ...changePoints, n];

		for (let i = 0; i < segments.length - 1; i++) {
			const start = segments[i] as unknown as number;
			const end = segments[i + 1] as unknown as number;
			const segmentValues = values.slice(start, end);
			const segmentDates = dates.slice(start, end);

			if (segmentValues.length > 1) {
				const segmentTrend = MathematicalFunctions.calculateTrend({
					values: segmentValues,
					dates: segmentDates,
				});

				for (let j = 0; j < segmentTrend.length; j++) {
					trend[start + j] = segmentTrend[j] as unknown as number;
				}
			} else if (segmentValues.length === 1) {
				trend[start] = segmentValues[0] as unknown as number;
			}
		}

		return trend;
	}

	private generateDateRange({
		startDate,
		endDate,
		count,
	}: {
		startDate: string;
		endDate: string;
		count: number;
	}): string[] {
		const start = new Date(startDate);
		const end = new Date(endDate);
		const totalDays =
			Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
		const step = totalDays / count;

		const dates: string[] = [];
		for (let i = 0; i < count; i++) {
			const currentDate = new Date(start.getTime() + i * step * 24 * 60 * 60 * 1000);
			const dateArr = currentDate.toISOString().split('T') as [string, string];
			dates.push(dateArr[0]);
		}
		return dates;
	}

	private createComprehensiveForecast({
		yearlyComponent,
		monthlyComponent,
		weeklyComponent,
		quarterlyComponent,
		trendComponent,
		smoothedResidualsArr,
		historicalLength,
		forecastDays,
		endDate,
	}: {
		yearlyComponent: number[];
		monthlyComponent: number[];
		weeklyComponent: number[];
		quarterlyComponent: number[];
		trendComponent: number[];
		smoothedResidualsArr: number[];
		historicalLength: number;
		forecastDays: number;
		endDate: string;
		purchasesArr: number[];
	}): {
		forecastValues: number[];
		forecastDates: string[];
		components: {
			yearly: number[];
			monthly: number[];
			weekly: number[];
			quarterly: number[];
			trend: number[];
			residuals: number[];
		};
	} {
		const forecastDates = this.generateFutureDates({ endDate, forecastDays });

		const harmonics = this.getHarmonicsByObservationsCount({
			observations: historicalLength,
		});

		const extendedYearly = this.extendSeasonalComponent({
			component: yearlyComponent,
			period: 365,
			harmonics,
			historicalLength,
			forecastDates,
			endDate,
		});
		const extendedMonthly = this.extendSeasonalComponent({
			component: monthlyComponent,
			period: 30,
			harmonics,
			historicalLength,
			forecastDates,
			endDate,
		});
		const extendedWeekly = this.extendSeasonalComponent({
			component: weeklyComponent,
			period: 7,
			harmonics,
			historicalLength,
			forecastDates,
			endDate,
		});
		const extendedQuarterly = this.extendSeasonalComponent({
			component: quarterlyComponent,
			period: 91,
			harmonics,
			historicalLength,
			forecastDates,
			endDate,
		});

		const extendedResiduals = this.extendResidualsComponent({
			smoothedResidualsArr,
			forecastDays,
			endDate,
		});

		const extendedTrend = this.extendTrendComponent({ trendComponent, forecastDays });

		const forecastValues = Array(forecastDays)
			.fill(0)
			.map((_, i) => {
				const yearly = extendedYearly[i] ?? 0;
				const monthly = extendedMonthly[i] ?? 0;
				const weekly = extendedWeekly[i] ?? 0;
				const quarterly = extendedQuarterly[i] ?? 0;
				const trend = extendedTrend[i] ?? 0;
				const residual = extendedResiduals[i] ?? 0;
				const forecastValue = trend + yearly + monthly + weekly + quarterly + residual;
				return Math.max(0, forecastValue);
			});

		return {
			forecastValues,
			forecastDates,
			components: {
				yearly: extendedYearly,
				monthly: extendedMonthly,
				weekly: extendedWeekly,
				quarterly: extendedQuarterly,
				trend: extendedTrend,
				residuals: extendedResiduals,
			},
		};
	}

	private getHarmonicsByObservationsCount({
		observations,
	}: {
		observations: number;
	}): number {
		if (observations <= 800) return 8;
		return 4;
	}

	private extendSeasonalComponent({
		component,
		period,
		harmonics,
		historicalLength,
		forecastDates,
		endDate,
	}: {
		component: number[];
		period: number;
		harmonics: number;
		historicalLength: number;
		forecastDates: string[];
		endDate: string;
	}): number[] {
		if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];

		try {
			const coefficients = MathematicalFunctions.fourierCoefficients({
				values: component,
				period,
				harmonics,
				precision: null,
			});

			const forecastValues: number[] = [];
			const endDateObj = new Date(endDate);

			for (const forecastDate of forecastDates) {
				const forecastDateObj = new Date(forecastDate);

				const daysDiff = Math.floor(
					(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
				);

				const cyclePosition = (historicalLength + daysDiff) % period;
				const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
					period,
					harmonics,
					a: coefficients.a,
					b: coefficients.b,
					length: Math.ceil(cyclePosition) + 1,
					a0: 0,
				});

				const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
				forecastValues.push(seasonalValue);
			}

			return forecastValues;
		} catch (error) {
			this.logger.error(
				`Error extending seasonal component: ${(error as Error).message}`,
				(error as Error).stack,
			);
			return forecastDates.map((forecastDate) => {
				const endDateObj = new Date(endDate);
				const forecastDateObj = new Date(forecastDate);
				const daysDiff = Math.floor(
					(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
				);
				const flooredPeriod = Math.max(1, Math.floor(period));
				const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
				const historicalIndex = Math.min(cyclePosition, component.length - 1);
				return component[historicalIndex] ?? 0;
			});
		}
	}

	private extendTrendComponent({
		trendComponent,
		forecastDays,
	}: {
		trendComponent: number[];
		forecastDays: number;
	}): number[] {
		if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];

		const recentTrendPoints = Math.min(30, trendComponent.length);
		const recentTrend = trendComponent.slice(-recentTrendPoints);

		const x = Array.from({ length: recentTrend.length }, (_, i) => i);
		const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });

		const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
		const trendSlope = regression.slope;

		return Array(forecastDays)
			.fill(0)
			.map((_, i) => {
				const decay = Math.exp(-0.02 * i);
				return lastValue + trendSlope * (i + 1) * decay;
			});
	}

	private extendResidualsComponent({
		smoothedResidualsArr,
		forecastDays,
		endDate,
	}: {
		smoothedResidualsArr: number[];
		forecastDays: number;
		endDate: string;
	}): number[] {
		if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
			return Array(forecastDays).fill(0) as number[];
		}

		const twoWeeksLength = 7;
		const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
		const recentResiduals = smoothedResidualsArr.slice(-trendLength);

		const endDateObj = new Date(endDate);
		const dates = recentResiduals.map((_, i) => {
			const date = new Date(endDateObj);
			date.setDate(endDateObj.getDate() - (trendLength - i - 1));
			const dateArr = date.toISOString().split('T') as [string, string];
			return dateArr[0];
		});

		const trendValues = MathematicalFunctions.calculateTrend({
			values: recentResiduals,
			dates,
		});

		if (trendValues.length === 0) {
			return Array(forecastDays).fill(0) as number[];
		}

		const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
		const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });

		const lastIndex = recentResiduals.length - 1;
		return Array(forecastDays)
			.fill(0)
			.map((_, i) => {
				return regression.slope * (lastIndex + i + 1) + regression.intercept;
			});
	}

	private getDayOfYear(date = new Date()) {
		const start = new Date(Date.UTC(date.getFullYear(), 0, 1));
		const current = new Date(
			Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()),
		);

		return Math.floor((current.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
	}

	private generateFutureDates({
		endDate,
		forecastDays,
	}: {
		endDate: string;
		forecastDays: number;
	}): string[] {
		const dates: string[] = [];
		const startDate = new Date(endDate);

		for (let i = 1; i <= forecastDays; i++) {
			const futureDate = new Date(startDate);
			futureDate.setDate(startDate.getDate() + i);
			const dateArr = futureDate.toISOString().split('T') as [string, string];
			dates.push(dateArr[0]);
		}

		return dates;
	}

	private calculateTrendingReason({
		comprehensiveForecast,
		historicalOrders,
		trendComponent,
	}: {
		comprehensiveForecast: {
			forecastValues: number[];
			forecastDates: string[];
			components: {
				yearly: number[];
				monthly: number[];
				weekly: number[];
				quarterly: number[];
				trend: number[];
				residuals: number[];
			};
		};
		historicalOrders: number[];
		trendComponent: number[];
	}): { trendingReason: string; growthRate: number } {
		if (
			historicalOrders.length === 0 ||
			comprehensiveForecast.forecastValues.length === 0
		) {
			return { trendingReason: 'Stable pattern', growthRate: 0 };
		}

		const historicalAvg =
			historicalOrders.reduce((sum, val) => sum + val, 0) / historicalOrders.length;
		const forecastAvg =
			comprehensiveForecast.forecastValues.reduce((sum, val) => sum + val, 0) /
			comprehensiveForecast.forecastValues.length;

		const growthRate =
			historicalAvg > 0 ? (forecastAvg - historicalAvg) / historicalAvg : 0;

		const trendSlope = this.calculateTrendSlope({ trendComponent });

		if (growthRate > 0.2 || forecastAvg > historicalAvg * 1.2) {
			return { trendingReason: 'Strong growth forecast', growthRate };
		} else if (growthRate > 0.1 || forecastAvg > historicalAvg * 1.1) {
			return { trendingReason: 'Moderate growth forecast', growthRate };
		} else if (growthRate > 0 || trendSlope >= 0.05) {
			return { trendingReason: 'Positive trend detected', growthRate };
		} else {
			return { trendingReason: 'Stable pattern', growthRate };
		}
	}

	private calculateTrendSlope({ trendComponent }: { trendComponent: number[] }): number {
		if (trendComponent.length < 2) return 0;

		const recentPoints = Math.min(14, trendComponent.length);
		const recentTrend = trendComponent.slice(-recentPoints);

		const x = Array.from({ length: recentTrend.length }, (_, i) => i);
		const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });

		return regression.slope;
	}
}

